var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"마차가 멈췄어요. 수도원에 도착했나 봐요.","JPN":"馬車が止まりました。修道院に着いたようですね。","ENG":"The carriage stopped! We must've arrived at the monastery!","TWN":"馬車停了。好像到修道院了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그럴까요? 여기가 수도원이면 저희더러 내리라고 한마디 할 만도 한데.","JPN":"そうなのでしょうか？　ここが修道院なら、私たちに降りろと一言いうはずですわ。","ENG":"Perhaps. But if this were the monastery, the driver would have told us that, no?","TWN":"是嗎？可如果這裡是修道院的話，應該會讓我們下車才對。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"혹시라도 인신매매 같은 범죄에 연루되진 않았겠죠?","JPN":"まさか人身売買のような犯罪に巻き込まれたのでは？","ENG":"What if we are caught in the middle of a human trafficking crime?","TWN":"我們不會被牽扯進拐賣人口的犯罪吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"뭘 궁시렁거리고 있어. 그냥 내려서 확인하면 될 것 가지고.","JPN":"何をぶつぶつ言ってんだよ。降りて確認したらいいじゃん。","ENG":"What are you muttering about? Just step out and check.","TWN":"在嘀嘀咕咕什麼，直接下去看看不就行了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"응? 여기가 수도원이 있는 영지야, 부학회장?","JPN":"うん？　ここが修道院がある領地なの？　副学会長。","ENG":"Hmm? Are you sure this is the right place, Vice President?","TWN":"嗯？這裡是修道院所在的領地嗎，副學會長？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그걸 저한테 물어 보는 건가요. 길을 안다고 한 사람은 당신이잖아요.","JPN":"それを私に聞くのですか？　道を知っていると言ったのはあなたでしょう？","ENG":"Why are you asking me? You said you knew how to get there.","TWN":"你是在問我嗎？說認識路的人不是你嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"운전사 분도 안 보이세요. 다른 외지인에게 살해당하시진 않았겠죠?","JPN":"運転手さんも見当たりませんね。まさか、他の者に殺されたなんてことないですよね？","ENG":"The driver's gone missing too. We're not going to get murdered by another outlander, are we?","TWN":"司機也不見了呢。不會是被別的外地人殺了吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사장님, 뭔가 짚이는 게 있나요?","JPN":"社長、何か心当たりでも？","ENG":"Is there something on your mind, Boss?","TWN":"老闆，你猜到什麼了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나보다는 맥크레디 양 자네가 잘 알 것 같네만.","JPN":"私よりマクレディー君、君が知っているんじゃないか？","ENG":"I think you'll know better than I will, Regina.","TWN":"麥克蕾蒂，你好像應該比我更清楚吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"학회의 영지에 대해서라면 부학회장이 더 박식하겠지.","JPN":"学会の領地に関することなら副学会長の方がよく知っているはずだ。","ENG":"The Society's Vice President should be more knowledgeable about its estate.","TWN":"關於學會的領地，副學會長應該更了解才對。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"영지요? 그거라면…….","JPN":"領地ですか？　それなら……","ENG":"Estate? If you are talking abou–","TWN":"領地嗎？那樣的話……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그러고 보니, 저택 지하에 보관된 자료들을 검토하면서 본 기억이 있어요.","JPN":"そういえば、邸宅の地下に保管されている資料を検討した時に見た記憶がありますわ。","ENG":"Come to think of it, I do remember reviewing records stored in the mansion's basement.","TWN":"你這麼一說我想起來了，我記得我在研究宅邸地下保管的資料時看到過。"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어떤 측면에서는…… 네. 인정하고 말았죠.","JPN":"ある側面では……はい。認めてしまいました。","ENG":"In some respects... Yes. I did admit it.","TWN":"在某些方面……嗯，我得承認。"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"가문의 선조들께서 집착했던 미신과 병적인 연구에 일말의 성과들도 있었다는 걸요.","JPN":"マクレディー家の先祖が執着していた迷信と病的な研究に、それなりの成果もあったということを。","ENG":"That my family's obsession with superstitions and horrific research had yielded results.","TWN":"家族的先祖們執著的迷信和病態研究，也取得了一些成果。"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>침식 현상은 인간의 본능에 각인된 감정을 투영한다.</color>","JPN":"<color=#ffd34c>侵食現象は人間の本能に刻印された感情を投影する。</color>","ENG":"<color=#ffd34c>Counterside Effect reflects the emotions engraved in human instinct.</color>","TWN":"<color=#ffd34c>侵蝕現象會投射刻印在人類本能中的感情。</color>"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>침식 현상은 침식파가 유입되어 발생한다.</color>","JPN":"<color=#ffd34c>侵食現象は侵食波が流入して発生する。</color>","ENG":"<color=#ffd34c>Counterside Effect is caused by an influx of Corruption ray.</color>","TWN":"<color=#ffd34c>侵蝕現象是由侵蝕波的流入引起的。</color>"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"다시 말해, 침식파를 유입시킬 수만 있다면…","JPN":"つまり、侵食波を流入させることができれば……","ENG":"In other words, if one could control the flow of Corruption ray...","TWN":"也就是說，只要能引入侵蝕波……"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어떤 조건을 조성했는지에 따라 침식 현상을 원하는 형태로 유도할 수 있다는 뜻이죠.","JPN":"どのような条件を作り上げるかによって、侵食現象を思うがままに誘導することができるということです。","ENG":"Then one could control the conditions to produce the desired type of Counterside Effect.","TWN":"就能根據不同組成條件，把侵蝕現象構建成想要的形態。"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇지. 우리가 갇혀 있던 곳도 그런 방식으로 만들어진 공간이었을 걸세.","JPN":"そうだ。我々が閉じ込められていた場所もそのような方法で作られた空間だったのだろう。","ENG":"Correct. The place we were trapped in was made using a similar method to that.","TWN":"是的。我們被關起來的地方，應該也是以這種方式構建的空間。"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"입맛대로 이야기를 만들어서 실제로 나타나게 한단 말이야?","JPN":"好きなように話を作って、実際に現れるようにするってこと？","ENG":"You mean they're creating stories as they see fit and making them appear in reality?","TWN":"隨便編個故事，然後讓它在現實中出現嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……네. 기괴한 소문이나 불길한 징조를 유포해서 만들어낸 공간. 그게 바로 학회가 지닌 영지들이에요.","JPN":"……ええ。奇怪な噂や不吉な兆しを広めて作り上げた空間。それが学会が治めている領地の数々ですわ。","ENG":"...Yes. A place created by circulating evil omens and disturbing strange rumors. That is what the Society's estates are.","TWN":"……是的，散佈奇怪謠言或不祥之兆的傳聞，創造出來的空間。那就是學會擁有的領地。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어째서 감금되어 있을 때는 떠올리지 못한 걸까요?","JPN":"どうして監禁されている時には思いつかなかったのでしょう？","ENG":"But how could I not have thought of that when I was first locked in there?","TWN":"我被監禁的時候怎麼就沒想到呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그 때 원리를 기억해냈으면 좀 더 유의미한 탈출 계획을 세울 수 있었을 텐데…….","JPN":"その時に原理を思い出せていたら、もっと効果のある脱出計画を立てられたのに……","ENG":"If that had come to mind at that time, I could have devised a more meaningful escape.","TWN":"當時如果想到這個原理，就能制定更有用的逃跑計畫了……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그럼 이 숲도 침식 현상이 퍼져 있다는 말이네.","JPN":"じゃあ、この森も侵食現象が広がってるってことだね。","ENG":"Then that means that this forest is also tainted with Counterside Effect.","TWN":"那也就是說，這片森林也被侵蝕現象覆蓋呢。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"응. 듣고 나니까 묘하게 익숙한 공기야.","JPN":"うん。聞いてみれば妙に覚えのある空気だ。","ENG":"Hmm... Now that you mention it, the air does feel somewhat familiar.","TWN":"嗯，聽你說完，感覺空氣莫名地熟悉。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다네. 평범한 숲은 아니겠지.","JPN":"そのとおり。ただの森ではないだろう。","ENG":"Correct. This is no ordinary forest.","TWN":"是啊。這裡應該不是普通的森林。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아마 초대 받지 않은 침입자를 쫓아내기 위한 일종의 방범 장치가 존재할 걸세.","JPN":"おそらく招待されていない侵入者を追い払うための、一種の防犯装置が存在しているはずだ。","ENG":"I believe it is a protective barrier of some kind to chase out any unwanted intruders.","TWN":"也許會有用來趕走不速之客的某種防盜裝置。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"영지에 침입한 외부인들도 숲에서 이상한 일을 겪는다고 했어요.","JPN":"領地に侵入した領地外の人も、森で奇妙な現象にあったと言っていました。","ENG":"The outlanders who trespassed on the estate also said that strange things happened in the forest.","TWN":"聽說入侵領地的外地人，在森林裡會遇到很多怪事。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"계속 같은 장소를 맴돈다거나, 바깥이랑 연락이 안 된다거나, 끔찍한 환각을 본다거나……","JPN":"ずっと同じ場所を巡りづつけたり、外と連絡がつかなくなったり、恐ろしい幻覚を見たり……","ENG":"Some reported going around in circles, communications going down, or even experiencing horrific hallucinations...","TWN":"會一直在同一個地方徘徊，或者和外面聯絡不上，又或者看到可怕的幻覺什麼的……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어쩌면 저희가 타고 온 이 트럭부터가 희생자를 유인하는 함정이었을지도 모르겠네요.","JPN":"ひょっとすると私たちが乗ってきたこのトラックからして、犠牲者をおびき寄せる罠だったのかもしれませんね。","ENG":"Perhaps the truck was used as bait to lure victims into the forest in the first place.","TWN":"說不定連我們乘坐的這輛卡車，都是引誘犧牲者的陷阱。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이런 오지까지 태워 주는 트럭 운전사와 돈도 안 받고 음식을 주는 어르신처럼 마음씨 좋은 분들을 연이어 만날 가능성은….","JPN":"こんな奥地まで乗せてくれるトラックの運転手やお金も貰わず食べ物を分けてくれる老人のように、心優しい方々に立て続けに会う可能性なんて……","ENG":"And the possibility of meeting both a driver willing to drive us as well as a store owner willing to give us free food...","TWN":"能接連遇到願意載我們來到這種偏僻地方的卡車司機，還有不收錢送我們食物的老人，怎麼可能總是遇到那種心地善良的人……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"상식적으로 매우 희박해요.","JPN":"常識的に考えてとても低いですから。","ENG":"It is extremely unlikely.","TWN":"照常理來說，這種機率是微乎其微。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내 생각엔 자네 상식의 기준도 조금 유별난 것 같네만.","JPN":"君の常識の基準も少々独特だと思うが。","ENG":"You know, I think your criteria for what constitutes common sense is also a little strange.","TWN":"我覺得你的常識標準好像也有點特別。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그럼 어떡해? 이대로 트럭에서 야영이라도 하게?","JPN":"じゃあどうする？　このままトラックで野宿でもするつもり？","ENG":"Then what do we do now? Do we camp out at the truck?","TWN":"那怎麼辦？就這樣在卡車上露營嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"차라리 그 폐가로 돌아가자, 응? 노숙은 춥고 힘들단 말이야!","JPN":"いっそあの廃屋に戻ろうよ、ね？　野宿は寒いし辛いしさ！","ENG":"Let's just go back to that run-down shop. I don't wanna sleep on the ground, please?","TWN":"乾脆回那個廢屋吧，好不好？露宿街頭可是又冷又累！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님, 방금 저쪽 수풀이 부스럭거렸어요.","JPN":"副学会長様、今あそこの茂みが動きました。","ENG":"Ma'am, I think there's something rustling over by those bushes.","TWN":"副學會長，剛才那邊的樹叢裡有動靜。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"누, 누구야?! 놀리지 말고 얼른 나와!","JPN":"だ、誰！？　ふざけてないで早く出てこい！","ENG":"W-who goes there?! S-show yourself!!","TWN":"是…是誰？！別嚇唬人，趕緊出來！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"지금까지 나눈 얘기대로라면… 짐승이나 평범한 사람은 아니겠네요.","JPN":"今までの話した内容どおりならば……動物や普通の人間ではなさそうですわね。","ENG":"From this conversation... it cannot be a beast or a normal human.","TWN":"如果按你剛才所說的話……應該不是野獸或普通人吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"낯선 곳에 온 여행자, 도중에 지나친 수상한 인물.","JPN":"見知らぬ地に来た旅行者、途中ですれ違った怪しい人物。","ENG":"Travelers in an unfamiliar location, passing suspicious people...","TWN":"來自陌生地方的旅行者，途中路過的可疑之人。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"꼭 영화의 한 장면 같군.","JPN":"まるで映画のワンシーンのようだな。","ENG":"Sounds like a scene out of a movie.","TWN":"好像電影中的場景啊。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"과거에는 가면을 쓴 살인마나 식인귀, 심령 현상이 상대였지만….","JPN":"過去には仮面をつけた殺人鬼や食人鬼、心霊現象がその相手だったが……","ENG":"It was all about masked murderers, cannibals, and paranormal activities, but...","TWN":"過去的對手是戴著面具的殺人魔或食人鬼、超心理現象……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"요즘은 더 확실하고 이해하기 쉬운 고난이 존재하지.","JPN":"最近はもっとはっきりと理解しやすい苦難があるな。","ENG":"There are more understandable difficulties these days.","TWN":"最近卻存在更確切、更容易理解的苦難。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇다면……","JPN":"だとすると……","ENG":"Then that means...","TWN":"那……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"침식체겠군요. 다들 제 옆에서 떨어지지 마세요!","JPN":"侵食体でしょうね。皆さん、私のそばから離れないでください！","ENG":"That those are C.O.s. Everyone, stay close to me!","TWN":"應該是侵蝕體。大家都別離開我身邊！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};